@app.post("/v1/expire")
def expire_key():
    auth_err = _require_auth(request)
    if auth_err:
        return jsonify(auth_err[0]), auth_err[1]

    payload = request.get_json(silent=True) or {}
    kind = payload.get("kind")
    key_id = payload.get("id")
    ttl = payload.get("ttl_seconds")

    if kind not in (KEYSPACE_SESSIONS, KEYSPACE_API_KEYS):
        return _json_error("invalid_kind", 400, allowed=[KEYSPACE_SESSIONS, KEYSPACE_API_KEYS])
    if not key_id or not isinstance(key_id, str):
        return _json_error("missing_id", 400)

    ttl = _clamp_ttl(ttl, DEFAULT_SESSION_TTL_SECONDS if kind == KEYSPACE_SESSIONS else DEFAULT_API_KEY_TTL_SECONDS)
    k = _key(kind, key_id)
    ok = redis_client.expire(k, ttl)
    return jsonify({"status": "ok", "updated": bool(ok), "ttl_seconds": ttl}), 200


